import React from 'react';
import { Link, useLocation } from 'react-router-dom';
import { useAuth } from '../../contexts/AuthContext';
import './Header.css';

const Header = () => {
  const { user, logout } = useAuth();
  const location = useLocation();

  // Check if we're in admin mode
  const isAdminMode = location.pathname.includes('/admin/') || location.pathname.includes('/standalone-admin');
  
  // Check if we're on standalone admin dashboard
  const isStandaloneAdmin = () => {
    const adminSession = JSON.parse(sessionStorage.getItem('adminSession'));
    return !!(adminSession && adminSession.isAdmin);
  };

  const handleLogout = () => {
    if (isStandaloneAdmin()) {
      // Clear admin session
      sessionStorage.removeItem('adminSession');
      window.location.href = '/standalone-admin';
    } else {
      // Regular user logout
      logout();
    }
  };

  // Don't show header at all for admin pages
  if (isAdminMode) {
    return null;
  }

  return (
    <header className="header">
      <div className="container">
        <div className="header-content">
          <div className="logo">
            <Link to="/">
              <h1>🧠 MindMatch</h1>
            </Link>
          </div>
          
          <nav className="nav">
            {user ? (
              <>
                <Link to="/dashboard" className="nav-link">Dashboard</Link>
                <Link to="/quiz" className="nav-link">Career Quiz</Link>
                <Link to="/quiz-history" className="nav-link">Quiz History</Link>
                <Link to="/mentors" className="nav-link">Find Mentors</Link>
                <Link to="/progress" className="nav-link">Progress</Link>
                <Link to="/how-it-works" className="nav-link">How It Works</Link>
                <div className="user-menu">
                  <span className="welcome-text">Hello, {user.name}</span>
                  <button onClick={handleLogout} className="logout-btn">
                    Logout
                  </button>
                </div>
              </>
            ) : (
              <div className="auth-links">
                <Link to="/login" className="nav-link">Login</Link>
                <Link to="/signup" className="nav-link signup-btn">Sign Up</Link>
              </div>
            )}
          </nav>
        </div>
      </div>
    </header>
  );
};

export default Header;
